import{c as n,S as a,j as t,m as h}from"./chunks/framework.8aa1YH_s.js";const m=JSON.parse('{"title":"Bài giảng","description":"","frontmatter":{},"headers":[],"relativePath":"admin/bai-giang.md","filePath":"admin/bai-giang.md","lastUpdated":0}'),l={name:"admin/bai-giang.md"};function e(o,i,g,r,c,d){return a(),t("div",null,[...i[0]||(i[0]=[h('<h1 id="bai-giang" tabindex="-1">Bài giảng <a class="header-anchor" href="#bai-giang" aria-label="Permalink to “Bài giảng”">​</a></h1><p><strong>Đường dẫn:</strong> <code>https://lamsonedutech.vn/admin/lesson/lesson</code></p><p>Bài giảng là <strong>đơn vị nội dung học</strong> mà học viên xem/nghe/đọc. Một bài giảng có thể là video, văn bản, file PDF, slide, hoặc kết hợp.</p><h2 id="danh-sach-bai-giang" tabindex="-1">Danh sách bài giảng <a class="header-anchor" href="#danh-sach-bai-giang" aria-label="Permalink to “Danh sách bài giảng”">​</a></h2><p>Cột chính:</p><ul><li>Tên bài</li><li>Khóa học / Chuyên đề liên kết</li><li>Loại nội dung (Video / Văn bản / File / Slide)</li><li>Thời lượng (đối với video)</li><li>Trạng thái (Công khai / Nháp)</li><li>Ngày tạo, Người tạo</li></ul><h2 id="tao-bai-giang" tabindex="-1">Tạo bài giảng <a class="header-anchor" href="#tao-bai-giang" aria-label="Permalink to “Tạo bài giảng”">​</a></h2><ol><li>Bấm <strong>Thêm bài giảng</strong>.</li><li>Điền: <ul><li><strong>Tên bài</strong></li><li><strong>Mô tả ngắn</strong></li><li><strong>Loại nội dung</strong>: Video / Văn bản / File / Slide / Mix</li></ul></li><li>Thêm nội dung tương ứng:</li></ol><h3 id="video" tabindex="-1">Video <a class="header-anchor" href="#video" aria-label="Permalink to “Video”">​</a></h3><ul><li>Tải video lên (mp4, dung lượng ≤ giới hạn của hệ thống, thường 500MB-2GB).</li><li>Hoặc nhúng video từ URL (YouTube, Vimeo, hệ thống lưu trữ riêng).</li><li>(Tùy chọn) thêm <strong>phụ đề</strong> (file .srt) và <strong>chương</strong> (timestamp - tiêu đề).</li></ul><h3 id="van-ban-rich-text" tabindex="-1">Văn bản / Rich text <a class="header-anchor" href="#van-ban-rich-text" aria-label="Permalink to “Văn bản / Rich text”">​</a></h3><ul><li>Sử dụng trình soạn thảo: định dạng, chèn ảnh, công thức toán (LaTeX), bảng, code.</li><li>Có thể dán thẳng từ Word - hãy &quot;paste plain&quot; để tránh dính định dạng lỗi.</li></ul><h3 id="file-pdf-slide" tabindex="-1">File / PDF / Slide <a class="header-anchor" href="#file-pdf-slide" aria-label="Permalink to “File / PDF / Slide”">​</a></h3><ul><li>Tải lên file.</li><li>Cấu hình <strong>cho phép tải về</strong> hay chỉ <strong>đọc online</strong>.</li></ul><h3 id="mix" tabindex="-1">Mix <a class="header-anchor" href="#mix" aria-label="Permalink to “Mix”">​</a></h3><ul><li>Kết hợp: video chính ở trên, văn bản tóm tắt và file PDF kèm bên dưới.</li></ul><ol start="4"><li><strong>Gán vào khóa / chuyên đề</strong> (chọn 1 hoặc nhiều).</li><li>(Tùy chọn) <strong>Thẻ / Từ khóa</strong> cho tìm kiếm.</li><li>Bấm <strong>Lưu</strong>.</li></ol><h2 id="chi-tiet-bai-giang" tabindex="-1">Chi tiết bài giảng <a class="header-anchor" href="#chi-tiet-bai-giang" aria-label="Permalink to “Chi tiết bài giảng”">​</a></h2><p><code>https://lamsonedutech.vn/admin/detailLesson/:id</code></p><p>Trang chi tiết cho phép:</p><ul><li>Preview như học viên đang xem.</li><li>Xem số lượt xem, thời gian xem trung bình.</li><li>Xem nhận xét của học viên (nếu cho phép comment).</li></ul><h2 id="phan-biet-voi-đe-kiem-tra" tabindex="-1">Phân biệt với &quot;Đề kiểm tra&quot; <a class="header-anchor" href="#phan-biet-voi-đe-kiem-tra" aria-label="Permalink to “Phân biệt với &quot;Đề kiểm tra&quot;”">​</a></h2><p>Bài giảng = <strong>học</strong>. Đề thi / Đề kiểm tra = <strong>kiểm tra</strong>.</p><p>Bài giảng không có chấm điểm, không có đáp án. Hệ thống chỉ ghi nhận <strong>đã xem / chưa xem</strong>, dùng cho tính tiến độ học.</p><h2 id="meo-noi-dung-tot" tabindex="-1">Mẹo nội dung tốt <a class="header-anchor" href="#meo-noi-dung-tot" aria-label="Permalink to “Mẹo nội dung tốt”">​</a></h2><ul><li><strong>Mỗi video nên 5-15 phút.</strong> Quá dài học viên mất tập trung.</li><li><strong>Tên bài rõ ràng</strong>: &quot;Bài 3 - Cách tìm đỉnh parabol&quot; tốt hơn &quot;Bài 3&quot;.</li><li><strong>Có file tóm tắt PDF</strong> kèm video - học viên có thể in / lưu lại.</li><li><strong>Có công thức bằng LaTeX</strong> thay vì ảnh chụp - hiển thị đẹp, copy được.</li></ul><h2 id="xoa-bai-giang" tabindex="-1">Xóa bài giảng <a class="header-anchor" href="#xoa-bai-giang" aria-label="Permalink to “Xóa bài giảng”">​</a></h2><ul><li>Trước khi xóa, kiểm tra bài có đang được gán vào khóa nào không. Nếu có, học viên đã xem rồi sẽ bị mất tiến độ.</li><li>Ưu tiên <strong>gỡ khỏi chuyên đề</strong> thay vì xóa nội dung.</li></ul><h2 id="tai-len-hang-loat-neu-co" tabindex="-1">Tải lên hàng loạt (nếu có) <a class="header-anchor" href="#tai-len-hang-loat-neu-co" aria-label="Permalink to “Tải lên hàng loạt (nếu có)”">​</a></h2><p>Nếu có tab <strong>Import / Tải lên hàng loạt</strong>:</p><ol><li>Tải template Excel/CSV.</li><li>Điền danh sách: tên bài, link video, mô tả.</li><li>Upload file → hệ thống tạo hàng loạt bài giảng.</li><li>Sau đó vào khóa để gán chuyên đề thủ công.</li></ol><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Video upload bị lỗi.</strong> → Kiểm tra định dạng (mp4/h264), dung lượng, đường truyền. Có thể dùng nén video trước (HandBrake) để giảm dung lượng.</p><p><strong>Video bị giật khi học viên xem.</strong> → Nên dùng dịch vụ streaming chuyên dụng và bật tự động chọn chất lượng (ABR). Liên hệ IT để kiểm tra CDN.</p><p><strong>Tôi muốn chỉnh sửa video sau khi đã đăng.</strong> → Có thể tải video mới đè lên hoặc đổi URL. Tất cả học viên đang xem sẽ thấy nội dung mới khi reload.</p>',35)])])}const u=n(l,[["render",e]]);export{m as __pageData,u as default};
